IF UpNo >0 AND IsFolder= FALSE THEN
	UPDATE Board_Boards SET SortNo=CurentNo WHERE SortNo=UpNo;
	UPDATE Board_Folders SET SortNo=UpNo WHERE FolderNo = board_downfolderbyuser.folderno ;

