			public."UF_ContactsDetail"(U.Seq,'number') AS Number,
			public."UF_ContactsDetail"(U.Seq,'group') AS GroupName
		FROM ContactsUser U
		WHERE RegUserNo = contacts_getoutfile.userno
		AND UseYn = 'Y'
		AND Seq IN (SELECT UserSeq FROM tabUser);
	END IF;
END;
$function$

