		);
		Seq := lastval();
		-- ===========================================
		PERFORM contacts_insertlistgroupcontact(Seq,Listgroup);

		-- ============================================
		-- 전화번호
		-- ============================================
		-- 임시테이블 생성
		CREATE TEMP TABLE tabNumber (IsDefault CHAR(1), Type TINYINT, TypeName varchar(50), Value varchar(50)) ON COMMIT DROP;
		-- 체크데이터 생성;


		ChkTelInfo := REPLACE(TelInfo,',','');
